import { useEffect, useMemo, useState } from 'react';
import { buildApiUrl } from '../utils/api';

const BOARD_SECTIONS = [
  {
    key: 'roomBookings',
    title: 'Room Bookings',
    endpoint: '/get_room_bookings',
    emptyMessage: 'No room bookings yet.',
    columns: [
      { key: 'room_name', label: 'Room' },
      { key: 'check_in', label: 'Check In' },
      { key: 'check_out', label: 'Check Out' },
      { key: 'payment_phone', label: 'Phone' },
    ],
  },
  {
    key: 'foodOrders',
    title: 'Food Orders',
    endpoint: '/get_food_orders',
    emptyMessage: 'No food orders yet.',
    columns: [
      { key: 'order_title', label: 'Order' },
      { key: 'preferred_date', label: 'Date' },
      { key: 'preferred_time', label: 'Time' },
      { key: 'payment_phone', label: 'Phone' },
    ],
  },
  {
    key: 'stayBookings',
    title: 'Stay Bookings',
    endpoint: '/get_stay_bookings',
    emptyMessage: 'No stay bookings yet.',
    columns: [
      { key: 'customer_name', label: 'Guest' },
      { key: 'room_type', label: 'Room Type' },
      { key: 'check_in', label: 'Check In' },
      { key: 'check_out', label: 'Check Out' },
    ],
  },
  {
    key: 'eventBookings',
    title: 'Event Requests',
    endpoint: '/get_event_bookings',
    emptyMessage: 'No event requests yet.',
    columns: [
      { key: 'name', label: 'Name' },
      { key: 'event_type', label: 'Event Type' },
      { key: 'event_date', label: 'Date' },
      { key: 'phone', label: 'Phone' },
    ],
  },
];

const formatAmount = (value) => `KSh ${Number(value || 0).toLocaleString()}`;

function AdminOperationsBoard() {
  const [records, setRecords] = useState({
    roomBookings: [],
    foodOrders: [],
    stayBookings: [],
    eventBookings: [],
  });
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    let active = true;

    async function loadBoard() {
      try {
        const responses = await Promise.all(
          BOARD_SECTIONS.map((section) =>
            fetch(buildApiUrl(section.endpoint), {
              credentials: 'include',
            }).then(async (response) => {
              const data = await response.json();
              if (!response.ok) {
                throw new Error(data.message || `Unable to load ${section.title.toLowerCase()}.`);
              }

              return data;
            })
          )
        );

        if (!active) {
          return;
        }

        setRecords({
          roomBookings: responses[0] || [],
          foodOrders: responses[1] || [],
          stayBookings: responses[2] || [],
          eventBookings: responses[3] || [],
        });
        setError('');
      } catch (requestError) {
        if (!active) {
          return;
        }

        setError(requestError.message || 'Unable to load the latest bookings and orders.');
      } finally {
        if (active) {
          setLoading(false);
        }
      }
    }

    loadBoard();

    return () => {
      active = false;
    };
  }, []);

  const stats = useMemo(() => {
    const totalFoodRevenue = records.foodOrders.reduce(
      (total, order) => total + Number(order.total_amount || 0),
      0
    );
    const totalRoomRevenue = records.roomBookings.reduce(
      (total, booking) => total + Number(booking.amount || 0),
      0
    );

    return [
      {
        label: 'Room Bookings',
        value: records.roomBookings.length,
        accent: 'admin-stat-card--amber',
        note: 'Recent paid room stays',
      },
      {
        label: 'Food Orders',
        value: records.foodOrders.length,
        accent: 'admin-stat-card--teal',
        note: 'Dining and room-service orders',
      },
      {
        label: 'Stay Requests',
        value: records.stayBookings.length,
        accent: 'admin-stat-card--blue',
        note: 'Booking estimate submissions',
      },
      {
        label: 'Event Requests',
        value: records.eventBookings.length,
        accent: 'admin-stat-card--rose',
        note: 'Conference and event inquiries',
      },
      {
        label: 'Room Revenue',
        value: formatAmount(totalRoomRevenue),
        accent: 'admin-stat-card--slate',
        note: 'Total from saved room bookings',
      },
      {
        label: 'Food Revenue',
        value: formatAmount(totalFoodRevenue),
        accent: 'admin-stat-card--olive',
        note: 'Total from saved food orders',
      },
    ];
  }, [records]);

  return (
    <section className="admin-board">
      <div className="admin-board__hero">
        <div>
          <p className="admin-board__eyebrow">Operations Dashboard</p>
          <h2>Bookings, orders, and guest activity in one professional view.</h2>
          <p>
            Monitor recent room reservations, food orders, stay requests, and event inquiries
            without leaving the admin workspace.
          </p>
        </div>
        <button type="button" className="admin-board__refresh" onClick={() => window.location.reload()}>
          Refresh Panel
        </button>
      </div>

      {error && <div className="alert alert-warning">{error}</div>}
      {loading && <div className="alert alert-info">Loading dashboard data...</div>}

      <div className="admin-stats-grid">
        {stats.map((stat) => (
          <article className={`admin-stat-card ${stat.accent}`} key={stat.label}>
            <span>{stat.label}</span>
            <strong>{stat.value}</strong>
            <small>{stat.note}</small>
          </article>
        ))}
      </div>

      <div className="admin-board__grid">
        {BOARD_SECTIONS.map((section) => {
          const items = records[section.key];

          return (
            <article className="admin-data-card" key={section.key}>
              <div className="admin-data-card__header">
                <div>
                  <p>{section.title}</p>
                  <h3>{items.length} records</h3>
                </div>
              </div>

              {items.length === 0 ? (
                <p className="admin-data-card__empty">{section.emptyMessage}</p>
              ) : (
                <div className="admin-table-wrap">
                  <table className="admin-table">
                    <thead>
                      <tr>
                        {section.columns.map((column) => (
                          <th key={column.key}>{column.label}</th>
                        ))}
                      </tr>
                    </thead>
                    <tbody>
                      {items.slice(0, 6).map((item, index) => (
                        <tr key={`${section.key}-${item.id || index}`}>
                          {section.columns.map((column) => (
                            <td key={column.key}>{item[column.key] || '-'}</td>
                          ))}
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}
            </article>
          );
        })}
      </div>
    </section>
  );
}

export default AdminOperationsBoard;
